// Time:  O(h * 2^n)
// Space: O(2^n)

class Solution {
public:
    int numberWays(vector<vector<int>>& hats) {
        static const int MOD = 1e9 + 7;
        static const int HAT_SIZE = 40;

        vector<vector<int>> hat_to_people(HAT_SIZE);
        for (int i = 0; i < hats.size(); ++i) {
            for (const auto& hat: hats[i]) {
                hat_to_people[hat - 1].emplace_back(i);
            }
        }
        vector<int> dp(1 << hats.size());
        dp[0] = 1;    
        for (const auto& people : hat_to_people) {
            for (int mask = dp.size() - 1; mask >= 0; --mask) {
                for (const int& p: people) {
                    if (mask & (1 << p)) {
                        continue;
                    }
                    dp[mask | (1 << p)] += dp[mask];
                    dp[mask | (1 << p)] %= MOD;
                }
            }
        }
        return dp.back();
    }
};

# Time:  O(h * 2^n)
# Space: O(2^n)

class Solution(object):
    def numberWays(self, hats):
        """
        :type hats: List[List[int]]
        :rtype: int
        """
        MOD = 10**9 + 7
        HAT_SIZE = 40
        hat_to_people = [[] for _ in xrange(HAT_SIZE)]
        for i in xrange(len(hats)):
            for h in hats[i]:
                hat_to_people[h-1].append(i)
        dp = [0]*(1<<len(hats))
        dp[0] = 1
        for people in hat_to_people:
            for mask in reversed(xrange(len(dp))):
                for p in people:
                    if mask & (1<<p):
                        continue
                    dp[mask | (1<<p)] += dp[mask]
                    dp[mask | (1<<p)] %= MOD
        return dp[-1]
